import { useState, useRef, useEffect } from 'react';
import { getIngredients } from '../services/gemini';

const SUGGESTIONS = [
  '🍫 Chocolate Cake',
  '🍝 Pasta Carbonara',
  '🍛 Chicken Biryani',
  '🥞 Pancakes',
  '🍕 Margherita Pizza',
  '🥗 Caesar Salad',
];

function ChatBox({ onIngredientsFound }) {
  const [messages, setMessages] = useState([
    { role: 'bot', text: "Hi! 👋 Tell me what you want to cook — I'll handle everything from ingredients to checkout automatically.\n\nYou can also tell me things like:\n• 'biryani for 4 people'\n• 'pasta, I'm allergic to dairy'\n• 'chocolate cake, budget £10'" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(true);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const addMsg = (role, text) => setMessages(prev => [...prev, { role, text }]);

  const handleSuggestion = (suggestion) => {
    const text = suggestion.replace(/^.{2}/, '').trim();
    setShowSuggestions(false);
    setInput('');
    runAgent(text);
  };

  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const text = input.trim();
    setInput('');
    setShowSuggestions(false);

    // If already done — handle correction
    if (done) {
      addMsg('user', text);
      setDone(false);
      addMsg('bot', 'Got it! Let me adjust that for you...');
      setLoading(true);
      try {
        const result = await getIngredients(text);
        addMsg('bot', `✅ ${result.reply}`);
        if (result.assumptions) {
          addMsg('bot', `📋 Updated assumptions: ${result.assumptions}`);
        }
        onIngredientsFound(result.ingredients, result.budget);
        setDone(true);
      } catch (e) {
        addMsg('bot', 'Something went wrong. Please try again!');
      }
      setLoading(false);
      return;
    }

    runAgent(text);
  };

  const runAgent = async (userMessage) => {
    addMsg('user', userMessage);
    setLoading(true);


    try {
      // Step 1 — call Gemini with full autonomous prompt
      const result = await getIngredients(userMessage);

      addMsg('bot', `✅ ${result.reply}`);

      // Step 3 — show what agent assumed
      if (result.assumptions) {
        addMsg('bot', `📋 My assumptions: ${result.assumptions}\n\nIf anything is wrong just type a correction — e.g. "make it for 4 people" or "I'm allergic to nuts".`);
      }

      addMsg('bot', `Found ${result.ingredients.length} ingredients. Searching Tesco now and auto-selecting the best products for you...`);

      setDone(true);
      onIngredientsFound(result.ingredients);

    } catch (e) {
      addMsg('bot', 'Something went wrong. Please try again!');
      setDone(false);
    }

    setLoading(false);
  };

  return (
    <div className="chatbox">
      <div
        className="messages"
        style={{ overflowY: 'auto', maxHeight: 400 }}
      >
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`} style={{ whiteSpace: 'pre-line' }}>
            {m.text}
          </div>
        ))}

        {loading && (
          <div className="plan-card">
            <div className="plan-header">🤖 Agent is working...</div>
            <div className="plan-row">
              <span className="plan-icon">🧾</span>
              <div>
                <div className="plan-label">Plan</div>
                <div className="plan-value">Analysing your request and building ingredient list</div>
              </div>
            </div>
            <div className="plan-row">
              <span className="plan-icon">🛒</span>
              <div>
                <div className="plan-label">Actions</div>
                <div className="plan-value">Will search Tesco and auto-select best products</div>
              </div>
            </div>
            <div className="plan-row">
              <span className="plan-icon">🔄</span>
              <div>
                <div className="plan-label">Fallback</div>
                <div className="plan-value">Will auto-substitute unavailable items</div>
              </div>
            </div>
            <div className="plan-row">
              <span className="plan-icon">👉</span>
              <div>
                <div className="plan-label">Next step</div>
                <div className="plan-value">You just review and confirm</div>
              </div>
            </div>
          </div>
        )}

        <div ref={bottomRef} />
      </div>

      {showSuggestions && !loading && (
        <div className="suggestions">
          <div className="suggestions-label">Popular recipes</div>
          <div className="chips">
            {SUGGESTIONS.map((s, i) => (
              <button key={i} className="chip" onClick={() => handleSuggestion(s)}>
                {s}
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="input-row">
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleSend()}
          placeholder={
            done
              ? "Type a correction e.g. 'make it for 4 people'..."
              : "e.g. chocolate cake for 2, vegan, budget £15..."
          }
          disabled={loading}
        />
        <button onClick={handleSend} disabled={loading}>
          {loading ? '...' : 'Send'}
        </button>
      </div>
    </div>
  );
}

export default ChatBox;
